use std::collections::HashMap;

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
enum HandshakeState {
    Initiating,
    WaitingForServerHello,
    KeyExchanged,
    Finished,
}

struct ConnectionHandler {
    current_state: HandshakeState,
    session_data: HashMap<String, String>,
}

impl ConnectionHandler {
    fn new() -> Self {
        ConnectionHandler {
            current_state: HandshakeState::Initiating,
            session_data: HashMap::new(),
        }
    }

    fn process_message(&mut self, message_type: &str) -> Result<(), String> {
        match self.current_state {
            HandshakeState::Initiating => {
                if message_type == "ServerHello" {
                    self.current_state = HandshakeState::WaitingForServerHello;
                    println!("State changed to WaitingForServerHello");
                    Ok(())
                } else {
                    Err(format!("Unexpected message type: {}", message_type))
                }
            },
            HandshakeState::WaitingForServerHello => {
                if message_type == "KeyExchange" {
                    self.current_state = HandshakeState::KeyExchanged;
                    println!("State changed to KeyExchanged");
                    Ok(())
                } else {
                    Err(format!("Unexpected message type: {}", message_type))
                }
            },
            HandshakeState::KeyExchanged => {
                if message_type == "Finished" {
                    self.current_state = HandshakeState::Finished;
                    println!("State changed to Finished");
                    Ok(())
                } else {
                    Err(format!("Unexpected message type: {}", message_type))
                }
            },
            HandshakeState::Finished => {
                if message_type == "Done" {
                    println!("Already fully connected.");
                    Ok(())
                } else {
                    Err(format!("Connection is already established."))
                }
            }
        }
    }
}

use std::collections::HashMap;

#[derive(Debug, Clone, Copy, PartialEq)]
enum EntityState {
    Idle,
    Patrolling,
    Engaged,
    Fleeing,
}

struct GameEntity {
    name: String,
    state: EntityState,
    health: i32,
    max_health: i32,
}
impl GameEntity {
    fn new(name: &str, health: i32) -> Self {
        GameEntity {
            name: name.to_string(),
            state: EntityState::Idle,
            health: health,
            max_health: health,
        }
    }

    fn process_tick(&mut self, target_is_visible: bool) -> Result<(), String> {
        let old_state = self.state;
        match self.state {
            EntityState::Idle => {
                if !target_is_visible && self.health < self.max_health {
                    self.state = EntityState::Patrolling;
                    Ok(())
                } else if target_is_visible {
                    self.state = EntityState::Engaged;
                    Ok(()) 
                } else {
                    Ok(())
                }
            },
            EntityState::Patrolling => {
                if !target_is_visible && self.health > 0 {
                    // Remains patrolling, no change needed for this tick
                    Ok(()) 
                } else if target_is_visible && self.health > 0 {
                    self.state = EntityState::Engaged;
                    Ok(()) 
                } else {
                    Ok(())
                }
            },
            EntityState::Engaged => {
                if self.health <= 0 {
                    self.state = EntityState::Fleeing;
                    Ok(()) 
                } else if !target_is_visible {
                    self.state = EntityState::Patrolling;
                    Ok(()) 
                } else {
                    Ok(())
                }
            },
            EntityState::Fleeing => {
                if self.health > 0 && target_is_visible {
                    self.state = EntityState::Engaged;
                    Ok(()) 
                } else if self.health <= 0 {
                    self.state = EntityState::Fleeing; // Stay in terminal state or handle death differently
                    Err(format!("{}: Deceased", self.name))
                } else {
                    Ok(())
                }
            }
        }
    }
}

fn main() {
    let mut goblin = GameEntity::new("Goblin", 10);
    println!("Initial State: {:?}", goblin.state); 

    goblin.process_tick(false).unwrap(); 
    println!("After initial check: {:?}", goblin.state); 

    goblin.process_tick(true).unwrap(); 
    println!("After seeing player: {:?}", goblin.state);

    goblin.process_tick(false).unwrap(); 
    println!("After losing sight (should revert): {:?}", goblin.state); 
}

use std::collections::HashMap;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct TokenType {
    is_number: bool,
    is_operator: bool,
    is_identifier: bool,
}

impl Default for TokenType {
    fn default() -> Self {
        TokenType { 
            is_number: false,
            is_operator: false,
            is_identifier: false
        }
    }
}

struct StateTracker {
    current_state: u32,
    last_token_type: TokenType,
}

impl StateTracker {
    fn new() -> Self {
        StateTracker { 
            current_state: 0,
            last_token_type: TokenType::default()
        }
    }

    fn update_state(&mut self, token_kind: &str) -> bool {
        if token_kind.starts_with("number") {
            self.last_token_type.is_number = true;
            self.current_state |= 1 << 0;
            return true;
        } else if token_kind.starts_with("operator") {
            self.last_token_type.is_operator = true;
            self.current_state |= 1 << 1;
            return true;
        } else if token_kind.starts_with("identifier") {
            self.last_token_type.is_identifier = true;
            self.current_state |= 1 << 2;
            return true;
        }
        false
    }

    fn print_status(&self) {
        println!("State Flags: {}", self.current_state);
        println!("Last Type: {:?}", self.last_token_type);
    }
}

fn main() {
    let mut tracker = StateTracker::new();

    tracker.update_state("number_read_123");
    tracker.print_status();

    tracker.update_state("operator_plus");
    tracker.print_status();

    tracker.update_state("identifier_myfunc");
    tracker.print_status();

    tracker.update_state("number_read_456");
    tracker.print_status();
}

