pub struct StateTracker {
    flags: u32,
}

impl StateTracker {
    pub fn new() -> Self {
        Self { flags: 0 }
    }

    pub fn add_flag(&mut self, flag: u32) {
        self.flags |= flag;
    }

    pub fn has_all_dependencies(&self, required_mask: u32) -> bool {
        (self.flags & required_mask) == required_mask
    }

    pub fn check_for_complete_state(self, complete_mask: u32) -> bool {
        self.has_all_dependencies(complete_mask)
    }
}

fn main() {
    let mut tracker = StateTracker::new();

    const FLAG_INITIALIZED: u32 = 1 << 0;
    const FLAG_DEPENDENCY_A: u32 = 1 << 1;
    const FLAG_VALIDATED: u32 = 1 << 2;
    const FLAG_READY: u32 = 1 << 3;

    tracker.add_flag(FLAG_INITIALIZED);
    tracker.add_flag(FLAG_DEPENDENCY_A);

    let required_for_run: u32 = FLAG_INITIALIZED | FLAG_DEPENDENCY_A;

    println!("Does it have enough to run? {}", tracker.has_all_dependencies(required_for_run));

    tracker.add_flag(FLAG_VALIDATED);

    let final_state: u32 = FLAG_INITIALIZED | FLAG_DEPENDENCY_A | FLAG_VALIDATED | FLAG_READY;
    println!("Is the system in its final state? {}", tracker.check_for_complete_state(final_state));
}

use std::collections::HashMap;
use std::sync::{Arc, Mutex};

struct ScoreboardState {
    connection_id: u64,
    score_map: HashMap<String, i32>,
}

impl Clone for ScoreboardState {
    fn clone(&self) -> Self {
        ScoreboardState {
            connection_id: self.connection_id,
            score_map: self.score_map.clone(),
        }
    }
}

impl ScoreboardState {
    fn new(id: u64) -> Self {
        ScoreboardState {
            connection_id: id,
            score_map: HashMap::new(),
        }
    }

    fn update_score(&mut self, team: &str, points: i32) -> Result<(), String> {
        if !self.is_connected() {
            return Err("Cannot update score: Not connected".to_string());
        }
        let entry = self.score_map.entry(team.to_string()).or_insert(0);
        *entry += points;
        Ok(())
    }

    fn is_connected(&self) -> bool {
        !self.score_map.is_empty()
    }
}

struct ConnectionManager {
    state: Mutex<ScoreboardState>,
}

impl ConnectionManager {
    fn new(id: u64) -> Self {
        ConnectionManager { state: Mutex::new(ScoreboardState::new(id)) }
    }

    fn handle_incoming_update(&self, team: &str, points: i32) -> Result<(), String> {
        let mut state = self.state.lock().unwrap();
        state.update_score(team, points)
    }

    fn get_current_state_snapshot(&self) -> ScoreboardState {
        self.state.lock().unwrap().clone()
    }
}
